const msg = $input.first().json;
const text = msg.message?.text || msg.message?.caption || '';
return [{
  json: {
    raw_text: text,
    chat_id: msg.message?.chat?.id,
    username: msg.message?.from?.username || 'unknown',
    timestamp: new Date().toISOString()
  }
}];

const resp = $input.first().json;
const prev = $('Extraer mensaje').first().json;

let intent;
try {
  const raw = resp.result || '{}';
  const cleaned = raw.replace(/```json\n?/g,'').replace(/```/g,'').trim();
  intent = JSON.parse(cleaned);
} catch(e) {
  intent = { intent: 'CHAT', confidence: 0.5, use_claude: false };
}

const route = intent.use_claude ? 'CLAUDE' : intent.intent;

return [{
  json: {
    ...prev,
    intent: intent.intent || 'CHAT',
    confidence: intent.confidence || 0.5,
    use_claude: intent.use_claude || false,
    route
  }
}];

